// Package grpc contains the inbound ConnectRPC adapter for the crop-service.
// NOTE: proto types are generated by buf generate.
package grpc

import (
	"context"

	"p9e.in/samavaya/packages/errors"
	"p9e.in/samavaya/packages/p9context"
	"p9e.in/samavaya/packages/p9log"

	// Generated by buf generate
	pb "p9e.in/samavaya/agriculture/crop-service/api/v1"
	"p9e.in/samavaya/agriculture/crop-service/internal/domain"
	"p9e.in/samavaya/agriculture/crop-service/internal/ports/inbound"
)

// CropHandler is the ConnectRPC inbound adapter.
type CropHandler struct {
	svc inbound.CropService
	log *p9log.Helper
}

// NewCropHandler creates a new ConnectRPC crop handler.
func NewCropHandler(svc inbound.CropService, log p9log.Logger) *CropHandler {
	return &CropHandler{
		svc: svc,
		log: p9log.NewHelper(p9log.With(log, "component", "CropHandler")),
	}
}

// CreateCrop handles creation requests.
func (h *CropHandler) CreateCrop(ctx context.Context, req *pb.CreateCropRequest) (*pb.CreateCropResponse, error) {
	h.log.Infow("msg", "CreateCrop request", "tenant_id", p9context.TenantID(ctx))
	if req.GetName() == "" {
		return nil, errors.BadRequest("INVALID_ARGUMENT", "name is required")
	}
	entity := &domain.Crop{Name: req.GetName()}
	created, err := h.svc.CreateCrop(ctx, entity)
	if err != nil {
		return nil, errors.ToConnectError(err)
	}
	return &pb.CreateCropResponse{Crop: cropToProto(created)}, nil
}

// GetCrop handles get requests.
func (h *CropHandler) GetCrop(ctx context.Context, req *pb.GetCropRequest) (*pb.GetCropResponse, error) {
	if req.GetId() == "" {
		return nil, errors.BadRequest("INVALID_ARGUMENT", "id is required")
	}
	entity, err := h.svc.GetCrop(ctx, req.GetId())
	if err != nil {
		return nil, errors.ToConnectError(err)
	}
	return &pb.GetCropResponse{Crop: cropToProto(entity)}, nil
}

// ListCrops handles list requests.
func (h *CropHandler) ListCrops(ctx context.Context, req *pb.ListCropsRequest) (*pb.ListCropsResponse, error) {
	params := domain.ListCropParams{PageSize: req.GetPageSize()}
	entities, total, err := h.svc.ListCrops(ctx, params)
	if err != nil {
		return nil, errors.ToConnectError(err)
	}
	protos := make([]*pb.Crop, 0, len(entities))
	for i := range entities {
		protos = append(protos, cropToProto(&entities[i]))
	}
	return &pb.ListCropsResponse{Crops: protos, TotalCount: total}, nil
}

// UpdateCrop handles update requests.
func (h *CropHandler) UpdateCrop(ctx context.Context, req *pb.UpdateCropRequest) (*pb.UpdateCropResponse, error) {
	if req.GetId() == "" {
		return nil, errors.BadRequest("INVALID_ARGUMENT", "id is required")
	}
	entity := &domain.Crop{}
	entity.UUID = req.GetId()
	updated, err := h.svc.UpdateCrop(ctx, entity)
	if err != nil {
		return nil, errors.ToConnectError(err)
	}
	return &pb.UpdateCropResponse{Crop: cropToProto(updated)}, nil
}

// DeleteCrop handles delete requests.
func (h *CropHandler) DeleteCrop(ctx context.Context, req *pb.DeleteCropRequest) (*pb.DeleteCropResponse, error) {
	if req.GetId() == "" {
		return nil, errors.BadRequest("INVALID_ARGUMENT", "id is required")
	}
	if err := h.svc.DeleteCrop(ctx, req.GetId()); err != nil {
		return nil, errors.ToConnectError(err)
	}
	return &pb.DeleteCropResponse{Success: true}, nil
}

func cropToProto(e *domain.Crop) *pb.Crop {
	return &pb.Crop{
		Id:       e.UUID,
		TenantId: e.TenantID,
		Name:     e.Name,
		Status:   string(e.Status),
	}
}
